const f=$input.first().json;
const cb=(v)=> !!(Array.isArray(v)? v.length : v);
return [{json:{
  target_id: String(f['Target Course ID']||'').trim(),
  email: f['Email'],
  modules:{
    a7: cb(f['Transcripts / Dubbing (A7)']),
    a8: cb(f['Images (A8)']),
    a9: cb(f['Annexes (A9)']),
    a10: cb(f['Liens (A10)'])
  },
  started_at: new Date().toISOString()
}}];

const ip=$('Init Params').first().json;
const target=ip.target_id;
const tree=($('Find P1 (GitHub Tree)').first().json.tree)||[];
const re=new RegExp('07_runs/(\\d+)/output/'+target+'_localized_(.+)\\.html$');
let found=null;
for(const t of tree){ const m=(t.path||'').match(re); if(m){ found={path:t.path, source_id:m[1], direction:m[2]}; break; } }
if(!found) return [{json:{...ip, phase1_ready:false}}];
const RAW='https://raw.githubusercontent.com/jeremieborrotzu-blip/Ressources_Loc_OSS/main/';
const od='07_runs/'+found.source_id+'/output/';
const enc=(p)=>RAW+encodeURIComponent(p).replace(/%2F/g,'/');
// handoff présent ?
const hasHandoff=tree.some(t=>t.path===od+target+'_phase1_handoff.json');
return [{json:{
  ...ip, phase1_ready:true, source_id:found.source_id, direction:found.direction,
  html_path:found.path,
  html_url:enc(found.path),
  handoff_present:hasHandoff,
  handoff_url:enc(od+target+'_phase1_handoff.json'),
  output_dir:od
}}];

const j=$input.first().json;
return [{json:{...j, error_html:`<h2>LEO Assets — Phase 1 introuvable</h2>
<p>Aucun HTML localisé trouvé pour le Target ID <b>${j.target_id}</b> dans <code>07_runs/*/output/${j.target_id}_localized_*.html</code>.</p>
<p>Lance d'abord la <b>Phase 1</b> (localisation HTML) pour ce cours, puis relance les Assets.</p>`}}];

const raw = $('Load Handoff').first().json;
const h = (typeof raw.data === 'string') ? JSON.parse(raw.data) : (raw.meta ? raw : JSON.parse(raw.content ? Buffer.from(raw.content,'base64').toString('utf8') : '{}'));
const loc = $('Locate Deliverables').first().json;
const banner = u => /banner/i.test(u||'');
const media = h.media_inventory || [];
// A8 — images
const images = media.filter(m => m.type==='image' && !banner(m.url));
const imagesToLocalize = images.filter(m => m.risk!=='ok');
// A7 — vidéos / screencasts (dubbing)
const videos = media.filter(m => ['video','screencast'].includes(m.type));
// A9 — annexes (docs)
const docExt = /\.(pdf|docx?|xlsx?|pptx?|csv)$/i;
const annexes = media.filter(m => ['pdf','docx','xlsx','pptx','csv','document','annex'].includes(m.type) || docExt.test(m.url||''));
// A10 — liens
const links = media.filter(m => m.type==='link');
return [{json:{
  target_course_id: h.meta.target_course_id,
  source_course_id: h.meta.source_course_id,
  direction: h.meta.direction,
  domain: h.meta.detected_domain,
  target_language: h.meta.target_language,
  email: loc.email,
  modules: loc.modules || {a7:false,a8:false,a9:false,a10:false},
  images_to_localize: imagesToLocalize,
  inventory: {
    videos: videos.map(m=>({url:m.url,location:m.location})),
    annexes: annexes.map(m=>({url:m.url,location:m.location,type:m.type})),
    links: links.map(m=>({url:m.url,location:m.location}))
  },
  counts:{ images_total:images.length, images_to_localize:imagesToLocalize.length, images_preserved:images.length-imagesToLocalize.length,
           videos:videos.length, annexes:annexes.length, links:links.length }
}}];

const ph=$('Parse Handoff').first().json;
const ic=$('Call Iconik Init').first().json;
const coll=ic.graphics_collection_id;
const a8on = !!(ph.modules && ph.modules.a8);
const list = a8on ? (ph.images_to_localize||[]) : [];
const items=list.map(m=>({json:{
  image_url:m.url, filename:(m.url.split('/').pop()||'image.png'),
  domain:ph.domain, target_language:ph.target_language,
  collection_id:coll, location:m.location, original_url:m.url
}}));
return items.length?items:[{json:{__no_images:true, collection_id:coll}}];

let a8=[];
try{ a8=$('Call A8').all().map(i=>i.json).filter(x=>x&&x.agent==='A8'); }catch(e){}
const ph=$('Parse Handoff').first().json;
const localized=a8.filter(r=>r.status==='localized');
const preserved=a8.filter(r=>r.status==='preserved');
return [{json:{
  target_course_id:ph.target_course_id, source_course_id:ph.source_course_id,
  direction:ph.direction, email:ph.email,
  a8:{ processed:a8.length, localized:localized.length, preserved:preserved.length, results:a8 }
}}];

const r = $('Collect Results').first().json;
const ph = $('Parse Handoff').first().json;
const mod = ph.modules || {};
const inv = ph.inventory || {videos:[],annexes:[],links:[]};
const a8rows = (r.a8.results||[]).map(x=>`<tr><td>${x.filename||''}</td><td>${x.status}</td><td>${x.asset_class||''}</td><td>${x.texts_localized||0}/${x.texts_preserved||0}</td><td>${x.iconik_asset_id||x.reason||''}</td></tr>`).join('');
const sec = (on, title, body) => `<h3>${on?'✅':'⬜'} ${title}</h3>${on?body:'<p><i>Non demandé (case décochée).</i></p>'}`;
const invList = (arr, empty) => arr.length ? `<ul>${arr.map(x=>`<li>${(x.url||'').split('/').pop()} <small>(${x.location||'?'})</small></li>`).join('')}</ul>` : `<p><i>${empty}</i></p>`;
const html = `<h2>LEO v1 — Assets : rapport</h2>
<p><b>Cours :</b> ${r.source_course_id} → ${r.target_course_id} | <b>Direction :</b> ${r.direction}</p>
${sec(mod.a8, `A8 — Images : ${r.a8.localized} localisées, ${r.a8.preserved} préservées (${r.a8.processed} traitées)`,
  `<table border=1 cellpadding=4><tr><th>Fichier</th><th>Statut</th><th>Type</th><th>Loc/Pres</th><th>Iconik / raison</th></tr>${a8rows}</table>
   <p>Uploadées dans Iconik : 0000_LOCALISATION/${r.target_course_id}/static_graphics/</p>`)}
${sec(mod.a7, `A7 — Transcripts / Dubbing (inventaire : ${inv.videos.length})`,
  invList(inv.videos,'Aucune vidéo dans le handoff.') + '<p><small>Traitement dubbing complet : build SUB dédié à venir.</small></p>')}
${sec(mod.a9, `A9 — Annexes (inventaire : ${inv.annexes.length})`,
  invList(inv.annexes,'Aucune annexe dans le handoff.') + '<p><small>Édition docs (XLSX/DOCX/PPTX/CSV) : build SUB dédié à venir.</small></p>')}
${sec(mod.a10, `A10 — Liens (inventaire : ${inv.links.length})`,
  invList(inv.links,'Aucun lien dans le handoff.') + '<p><small>Résolution liens FR→EN : build SUB dédié à venir.</small></p>')}`;
return [{json:{...r, html}}];

